1	interface Item {
2	  type: string;
3	}
4	
5	interface Policy {
6	  items: Item[];
7	  customer: { yearsWithMHPCO: number };
8	  isFollowUp: boolean;
9	}
10	
11	const PROCESSING_FEE = 5;
12	const FIRST_INSURANCE_RATE = 0.1;
13	const BASE_PREMIUM: Record<string, number> = { sword: 100, staff: 80, potion: 40, rune: 25, moonstone: 25 };
14	const DEFAULT_BASE_PREMIUM = 60;
15	
16	const BLOCK_SIZE = 3;
17	const BLOCK_PREMIUM = 60;
18	
19	function countByType(items: Item[]): Record<string, number> {
20	  const counts: Record<string, number> = {};
21	  for (const item of items) {
22	    counts[item.type] = (counts[item.type] ?? 0) + 1;
23	  }
24	  return counts;
25	}
26	
27	function itemGroupPremium(type: string, count: number): number {
28	  if (count === BLOCK_SIZE) {
29	    return BLOCK_PREMIUM;
30	  }
31	  return count * (BASE_PREMIUM[type] ?? DEFAULT_BASE_PREMIUM);
32	}
33	
34	export function quote(policy: Policy) {
35	  const counts = countByType(policy.items);
36	
37	  let basePremium = 0;
38	  for (const [type, count] of Object.entries(counts)) {
39	    basePremium += itemGroupPremium(type, count);
40	  }
41	
42	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
43	  const premium = Math.ceil(basePremium + firstInsuranceSurcharge + PROCESSING_FEE);
44	  return { premium };
45	}
46	
